INSERT INTO swipecheck_questions (id, category, mode, order_index, text, options_json)
VALUES
  (43, 'cabinetry', 'lite', 1, 'What is the first thing you should inspect when examining your cabinets for potential issues?', '["Check for visible surface damage like scratches or dents","Ensure all cabinet doors and drawers open and close smoothly","Look for any evidence of water damage or moisture","Test the stability of each cabinet when gently pushed"]'::jsonb),
  (44, 'cabinetry', 'lite', 2, 'How can you identify if there might be a moisture problem within your cabinetry?', '["Look for discoloration or swelling of the wood","Check for a musty smell inside the cabinets","Inspect for signs of mold or mildew growth","All of the above"]'::jsonb),
  (45, 'cabinetry', 'lite', 3, 'What should you do if you notice screws or hinges are coming loose in your cabinet doors?', '["Ignore it unless the door falls off","Tighten the screws and check if the door aligns properly","Replace the door entirely","Use adhesive to keep the screws in place"]'::jsonb),
  (46, 'cabinetry', 'lite', 4, 'How can you tell if your cabinets might be infested with pests?', '["Find small holes or sawdust around the cabinets","Hear scratching noises coming from inside the cabinets","Notice chewed or frayed cabinet surfaces","Notice an odd chemical smell"]'::jsonb),
  (47, 'cabinetry', 'lite', 5, 'What is a good indication that the finish or paint on your cabinets is deteriorating?', '["Peeling or bubbling surface","Fading colors or uneven texture","Sticky residue on your hands after touching","The cabinets look dirty"]'::jsonb),
  (67, 'test', 'lite', 1, 'Take a look at the area around the windows. What do you notice?', '["Clear and dry","Foggy or condensation present","Watermarks appearing"]'::jsonb),
  (68, 'test', 'lite', 2, 'Inspect beneath the kitchen sink. What do you see around the pipes?', '["Dry and dusty","Damp or dark spots","Active dripping"]'::jsonb),
  (69, 'test', 'lite', 3, 'Observe the walls in the basement. What do you see on their surfaces?', '["Clean and smooth","Discolored patches","Efflorescence (white powdery substance)"]'::jsonb),
  (70, 'test', 'lite', 4, 'Look at the roof shingles from a safe distance. What do you notice about their appearance?', '["Uniform and flat","Curled edges","Missing shingles"]'::jsonb),
  (71, 'test', 'lite', 5, 'Examine the floor around the toilet base. What do you observe there?', '["Dry and stable","Water pooling","Warped or discolored"]'::jsonb),
  (73, 'project_rescue', 'lite', 10, 'What was the original goal of this project?', '["New Construction","Renovation/Remodel","Repair","Cosmetic Update"]'::jsonb),
  (74, 'project_rescue', 'lite', 20, 'What is the current status?', '["Not Started","In Progress","Stalled/Ghosted","Completed but Poorly"]'::jsonb),
  (75, 'project_rescue', 'lite', 30, 'Do you have the original contract or plans?', '["Yes","I have everything","Some documentation","No","it was a verbal agreement"]'::jsonb),
  (76, 'project_rescue', 'lite', 40, 'What is your biggest concern right now?', '["Quality of work","Incomplete work","Contractor communication","Cost overruns"]'::jsonb),
  (77, 'project_rescue', 'lite', 10, 'What was the original goal of this project?', '["New Construction","Renovation/Remodel","Repair","Cosmetic Update"]'::jsonb),
  (78, 'project_rescue', 'lite', 20, 'What is the current status?', '["Not Started","In Progress","Stalled/Ghosted","Completed but Poorly"]'::jsonb),
  (79, 'project_rescue', 'lite', 30, 'Do you have the original contract or plans?', '["Yes","I have everything","Some documentation","No","it was a verbal agreement"]'::jsonb),
  (80, 'project_rescue', 'lite', 40, 'What is your biggest concern right now?', '["Quality of work","Incomplete work","Contractor communication","Cost overruns"]'::jsonb),
  (91, 'rough_systems', 'lite', 1, 'Take a look at the electrical panel, what do you notice about the wiring inside?', '["Neat and organized","Tangled wires","Signs of wear or fraying"]'::jsonb),
  (92, 'rough_systems', 'lite', 2, 'Examine the area around the base of the water heater, what do you see?', '["Dry and clean","Damp spots","Puddles of water"]'::jsonb),
  (93, 'rough_systems', 'lite', 3, 'Observe the pipes in the basement, particularly at the joints and connections, what catches your eye?', '["No visible issues","Corrosion or rust","Wet or dripping areas"]'::jsonb),
  (94, 'rough_systems', 'lite', 4, 'Look at the HVAC ductwork, especially at seams and joints. What do you observe?', '["Secure and tight","Gaps or openings","Duct tape patches"]'::jsonb),
  (95, 'rough_systems', 'lite', 5, 'Inspect the main support beams in the basement or crawlspace, what do you notice about their condition?', '["Solid with no signs of damage","Cracks or splits","Signs of rot or insect damage"]'::jsonb),
  (314, 'kitchen', 'lite', 1, 'Do you see any water where it shouldn''t be (under the sink, around the dishwasher, or near the fridge water line)?', '["Looks dry","A little moisture","Water stains / swelling","Active leak right now"]'::jsonb),
  (315, 'kitchen', 'lite', 2, 'How does the kitchen sink drain (and disposal, if you have one)?', '["Drains fast","A bit slow","Backs up / gurgles","Not sure / no disposal"]'::jsonb),
  (316, 'kitchen', 'lite', 3, 'How is the dishwasher behaving?', '["Runs and drains normally","Leaves water / drains slowly","Leaks during or after a run","Not sure / no dishwasher"]'::jsonb),
  (317, 'kitchen', 'lite', 4, 'Are counter outlets protected by a TEST/RESET outlet (GFCI) and working?', '["Protected and works","Protected but trips / won''t reset","Not protected","Not sure"]'::jsonb),
  (318, 'kitchen', 'lite', 5, 'When do you want to tackle this?', '["ASAP","1–3 months","3–6 months","6+ months"]'::jsonb),
  (319, 'kitchen', 'full', 1, 'Do you see any water where it shouldn''t be (under the sink, around the dishwasher, or near the fridge water line)?', '["Looks dry","A little moisture","Water stains / swelling","Active leak right now"]'::jsonb),
  (320, 'kitchen', 'full', 2, 'How does the kitchen sink drain (and disposal, if you have one)?', '["Drains fast","A bit slow","Backs up / gurgles","Not sure / no disposal"]'::jsonb),
  (321, 'kitchen', 'full', 3, 'How is the dishwasher behaving?', '["Runs and drains normally","Leaves water / drains slowly","Leaks during or after a run","Not sure / no dishwasher"]'::jsonb),
