INSERT INTO swipe_checks (id, property_id, category, mode, answers_json, condition, condition_label, findings_json, summary_text, key_findings_json, gentle_guidance_json, recommended_contractor_type, suggested_timeframe, created_by_user_id, created_at, updated_at)
VALUES
  (4, 5, 'bathroom', 'lite', '{}'::jsonb, 'Fair', 'Fair', '["Some minor issues detected in your bathroom","Consider scheduling a professional inspection soon","Regular maintenance recommended"]'::jsonb, 'The bathroom is in a fair condition, with intact walls and ceiling, but potential issues with fixtures.', '["No water leaks observed from walls or ceiling.","Current bathroom fixtures are operational but show signs of wear."]'::jsonb, '["Regularly inspect fixtures for leaks or signs of wear.","Consider updating the faucet or showerhead if they show significant wear.","Check caulking around the bathtub or shower and reapply if necessary."]'::jsonb, NULL, NULL, 22, '2025-12-09T23:14:49.402Z', '2025-12-09T23:14:52.347Z'),
  (5, 5, 'kitchen', 'lite', '{}'::jsonb, 'Good', 'Good', '["Your kitchen appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The kitchen is currently in good condition with modern appliances under five years old, and no immediate signs of damage or malfunction.', '["Appliances are newer or under five years old.","No signs of leaks or water damage.","Overall appearance and function are good."]'::jsonb, '["Consider regular cleaning and maintenance to prolong the life of appliances.","Schedule periodic checks especially for larger appliances and plumbing."]'::jsonb, NULL, NULL, 22, '2025-12-09T23:17:18.931Z', '2025-12-09T23:17:22.020Z'),
  (6, 6, 'bathroom', 'lite', '{}'::jsonb, 'Fair', 'Fair', '["Some minor issues detected in your bathroom","Consider scheduling a professional inspection soon","Regular maintenance recommended"]'::jsonb, 'The bathroom is in fair condition with functional features, but certain elements need maintenance to improve its state.', '["Water leakages were not observed.","Plumbing fixtures are in good working order.","There are no signs of mold or mildew on the walls or ceiling."]'::jsonb, '["Check for any hidden water leaks periodically to prevent future issues.","Schedule routine maintenance for plumbing fixtures to ensure they remain in good condition."]'::jsonb, NULL, NULL, 8, '2025-12-09T23:18:08.870Z', '2025-12-09T23:18:12.087Z'),
  (7, 6, 'bathroom', 'lite', '{}'::jsonb, 'Fair', 'Fair', '["Some minor issues detected in your bathroom","Consider scheduling a professional inspection soon","Regular maintenance recommended"]'::jsonb, 'The bathroom is in fair condition with some signs of wear and potential moisture around the fixtures, although no immediate leaks are present.', '["No current leaks detected in the plumbing.","Signs of moisture are noted around bathroom fixtures.","Walls and ceiling are dry","indicating no signs of mold or surface damage."]'::jsonb, '["Check for any signs of mold development","especially in grout lines or corners.","Consider resealing around fixtures if moisture persists to prevent future leaks."]'::jsonb, 'Plumber', 'Within the next 1-2 months', 8, '2025-12-09T23:18:12.477Z', '2025-12-09T23:18:16.374Z'),
  (8, 5, 'flooring', 'lite', '{}'::jsonb, 'Good', 'Good', '["Your flooring appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The flooring is overall stable and in good condition, with some areas showing cosmetic wear and tear. This includes minor dents, scratches, and a few lifted sections, as well as several noticeable stains. However, there are no gaps or separations, which indicates good structural integrity.', '["Noticeable dents and scratches.","Lifted areas in some spots.","Occasional creaking of the floor.","Stains or discolorations present.","No gaps or separations between the flooring."]'::jsonb, '["Consider refinishing or repairing the floor surface to address dents and scratches.","Ensure lifted areas are secured to prevent further issues.","Clean and treat stains to improve appearance.","Monitor the creaking and address if it worsens."]'::jsonb, 'Flooring contractor', 'Within 6 months', 22, '2025-12-09T23:19:05.747Z', '2025-12-09T23:19:11.090Z'),
  (9, 5, 'flooring', 'lite', '{}'::jsonb, 'Good', 'Good', '["Your flooring appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The flooring is in generally good condition with minor issues that require monitoring and maintenance to maintain its appearance and functionality.', '["Noticeable dents and scratches on the floor surface.","Lifted areas in some sections of the flooring detected.","Occasional creaking noted but floor remains stable overall.","Several discoloration or stain areas present on the flooring."]'::jsonb, '["Consider a deep cleaning solution to address the stains and discolorations.","Use furniture pads or rugs to prevent further scratches or dents.","Inspect and address lifted areas to prevent further damage.","Reinforce creaky sections if the noise becomes more pronounced."]'::jsonb, 'flooring specialist', 'within the next 3 months', 22, '2025-12-09T23:19:10.468Z', '2025-12-09T23:19:15.183Z'),
