  (27, 21, 'windows_doors', 'lite', '{}'::jsonb, 'Good', 'Good', '["Your windows_doors appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The windows and doors in your home are currently in good condition, suggesting they are likely well-maintained and functioning properly.', '["Windows and doors are free from visible damage or operational issues.","No signs of drafts or seal failures noted.","Locks and handles appear to be in working order."]'::jsonb, '["Continue regular cleaning and inspection to preserve their condition.","Consider seasonal checks for drafts as seals can degrade over time."]'::jsonb, NULL, NULL, 25, '2025-12-18T01:34:06.564Z', '2025-12-18T01:34:09.273Z'),
  (28, 22, 'bathroom', 'lite', '{}'::jsonb, 'Good', 'Needs Attention', '["Your bathroom appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The bathroom exhibits several signs of moisture issues, such as discoloration and dampness on walls and ceilings, alongside visible water stains and mineral build-up. Peeling paint and the presence of mold are also noticeable, with instances of active dripping contributing to potential ongoing water damage.', '["Damp walls with discoloration","Presence of water stains and mineral deposits","Mold and discoloration on surfaces","Peeling paint with dark","possibly mold-marked spots","Active water dripping indicating possible leak"]'::jsonb, '["Address the water dripping issue urgently as it may lead to further water damage.","Check for possible sources of leaks such as faucet","pipes","or faulty sealing.","Improve ventilation in the bathroom to inhibit mold growth.","Consider cleaning mineral deposits and reapplying a waterproof sealant to affected areas.","Regularly inspect for increased signs of moisture and address promptly."]'::jsonb, 'Plumber', 'Within the next 2 weeks', 6, '2025-12-18T05:07:03.036Z', '2025-12-18T05:07:09.294Z'),
