  (69, 85077, 'bedroom', 'full', '{}'::jsonb, 'Good', 'Good', '["Your bedroom appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The bedroom is in good condition with no noticeable issues reported. Windows and locks are functioning properly, and the environment feels comfortable to the occupant.', '["No issues noticed in the bedroom","Windows open","close","and lock well"]'::jsonb, '["Keep an eye on any potential drafts or temperature changes","especially as seasons change.","Ensure windows remain operable and locks are functional for safety.","Consider checking for any less apparent signs of wear or hidden issues over time."]'::jsonb, 'General Contractor', NULL, 26, '2026-01-11T19:31:36.586Z', '2026-01-11T19:31:39.149Z'),
