  (81, 85077, 'roof', 'full', '{}'::jsonb, 'Good', 'Good', '["Your roof appears to be in good working condition","No major concerns identified during this check"]'::jsonb, 'The roof appears to be in generally good condition with no major issues noted. The small area that may have caught your attention doesn''t seem to be affecting the overall health of the roof.', '["No significant damage or wear observed.","A small area of concern noted","but not impacting roof''s function.","No visible pests or leaks found."]'::jsonb, '["Monitor the small area and check for changes after heavy rain.","Consider a routine inspection annually to catch early signs of wear."]'::jsonb, 'Roofing', 'No immediate action required; next routine check-up in a year.', 26, '2026-01-11T21:19:08.422Z', '2026-01-11T21:19:11.085Z'),
