-- ============================================================
-- Swipe Home MVP — Data Import
-- Generated: 2026-04-16T23:15:26.603Z
-- Run this in the Supabase SQL editor
-- ============================================================

-- Disable triggers during import to skip auth checks
SET session_replication_role = replica;

-- ── PROFILES ────────────────────────────────────────────────
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  email = EXCLUDED.email,
  role = EXCLUDED.role;

SELECT setval('profiles_id_seq', GREATEST(nextval('profiles_id_seq') - 1, 116));

-- ── CONTRACTORS ─────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

SELECT setval('contractors_id_seq', GREATEST(nextval('contractors_id_seq') - 1, 48));

-- ── CONTRACTOR LEADS ────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

SELECT setval('contractor_leads_id_seq', GREATEST(nextval('contractor_leads_id_seq') - 1, 27));

-- ── PROPERTIES (user-owned) ─────────────────────────────────
ON CONFLICT (id) DO NOTHING;

SELECT setval('properties_id_seq', GREATEST(nextval('properties_id_seq') - 1, 85106));

-- ── DIDPIDs (user-owned, 55 rows) ──────────────────────────
ON CONFLICT (id) DO NOTHING;

SELECT setval('didpids_id_seq', GREATEST(nextval('didpids_id_seq') - 1, 85097));

-- ── SWIPECHECK QUESTIONS ────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

SELECT setval('swipecheck_questions_id_seq', GREATEST(nextval('swipecheck_questions_id_seq') - 1, 461));

-- ── SWIPE CHECKS ────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

SELECT setval('swipe_checks_id_seq', GREATEST(nextval('swipe_checks_id_seq') - 1, 116));

-- Re-enable triggers
SET session_replication_role = DEFAULT;

-- Verify row counts
SELECT 'profiles' as table_name, COUNT(*) FROM profiles
UNION ALL SELECT 'contractors', COUNT(*) FROM contractors
UNION ALL SELECT 'properties', COUNT(*) FROM properties WHERE user_id IS NOT NULL
UNION ALL SELECT 'didpids', COUNT(*) FROM didpids
UNION ALL SELECT 'swipecheck_questions', COUNT(*) FROM swipecheck_questions
UNION ALL SELECT 'swipe_checks', COUNT(*) FROM swipe_checks;